DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_after_insert_consultation` AFTER INSERT ON `consultation` FOR EACH ROW BEGIN
    -- 1ï¸âƒ£ Declare variables and cursor first
    DECLARE v_token VARCHAR(500);
    DECLARE v_column_name VARCHAR(100);
    DECLARE done INT DEFAULT 0;
    DECLARE cur CURSOR FOR SELECT column_name, value FROM tmp_autocomplete WHERE value IS NOT NULL AND TRIM(value) <> '';
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    -- 2ï¸âƒ£ Temporary table must be created outside the DECLARE section
    CREATE TEMPORARY TABLE IF NOT EXISTS tmp_autocomplete (
        column_name VARCHAR(100),
        value VARCHAR(500)
    );

    -- 3ï¸âƒ£ Insert new consultation values
    INSERT INTO tmp_autocomplete (column_name, value)
    VALUES
        ('history', NEW.history),
        ('ear_exam', NEW.ear_exam),
        ('nose_exam', NEW.nose_exam),
        ('throat_exam', NEW.throat_exam),
        ('others_exam', NEW.others_exam),
        ('diagnosis', NEW.diagnosis),
        ('recommendations', NEW.recommendations),
        ('maxillofacial_exam', NEW.maxillofacial_exam),
        ('head_and_neck_exam', NEW.head_and_neck_exam);

    -- 4ï¸âƒ£ Process cursor loop
    OPEN cur;
    read_loop: LOOP
        FETCH cur INTO v_column_name, v_token;
        IF done THEN
            LEAVE read_loop;
        END IF;

        SET v_token = TRIM(v_token);
        IF v_token NOT IN ('AS','AD','AU') THEN
            IF EXISTS (SELECT 1 FROM autocomplete_entries WHERE column_name = v_column_name AND value = v_token) THEN
                UPDATE autocomplete_entries
                SET cnt = cnt + 1
                WHERE column_name = v_column_name AND value = v_token;
            ELSE
                INSERT INTO autocomplete_entries (column_name, value, cnt)
                VALUES (v_column_name, v_token, 1);
            END IF;
        END IF;
    END LOOP;

    CLOSE cur;

    DROP TEMPORARY TABLE IF EXISTS tmp_autocomplete;
END */;;
DELIMITER ;
