INSERT INTO `custom_a5` (`custom_a5_id`, `consultation_id`, `patient_id`, `content`, `created_at`) VALUES (2,0,2549,'CC: HOARSENESS\r\nIMPRESSION: VOCAL CORD NODULES\r\n\r\n> Please accomodate patient for FLEXIBLE LARYNGOSCOPY ON Dec. 26, 2025, 9 AM\r\n> Please decongest patient prior to procedure\r\n> Inform me once patient is in.\r\n> Thank you.','2025-12-22 14:07:19'),(3,0,2086,'CC: Throat discomfort\r\nImpression: Laryngo-pharyngeal Reflux\r\n\r\n>Please accomodate patient for flexible nasolaryngoscopy under local anesthesia\r\n>Decongest prior to procedure\r\n>Inform me once patient is in.\r\nThank you.','2025-12-27 11:15:07'),(4,0,2591,'TO: WESTERN VISAYAS MEDICAL CENTER\r\nDEPARTMENT OF ORL-HNS (OPD)\r\n\r\nPLEASE SCHEDULE PATIENT FOR TONSILLECTOMY AS SERVICE CASE. THANK YOU.','2026-01-15 14:19:17'),(5,0,2633,'TO: MEDICUS AMBULATORY HEALTHCARE\r\n8TH FLOOR MEDICUS CONDO \r\nMANDURRIAO ILOILO CITY\r\n\r\n>PLEASE ACCOMODATE PATIENT FOR EXCISION AND REPAIR OF KELOID LEFT HELIX UNDER LOCAL ANESTHESIA ON fEBRUARY 18, 2026\r\n>INFORM ME ONCE PATIENT IS IN.\r\n>THANK YOU.','2026-01-19 13:45:33'),(6,0,2785,'Dr. Abigail Salcedo\r\nPediatric ENT\r\n\r\nDear Abbey, \r\n\r\nReferring patient for further evaluation of nasal congestion and noisy breathing which was noted since birth. I suggested for flexible nasolaryngoscopy but i don\'t have the instrument, thus this referral. \r\nThank you!','2026-02-02 12:36:56'),(7,0,2590,'TO: Department of ORL-HNS (OPD)\r\nWestern Visayas Medical Center, \r\nMandurriao Iloilo City\r\n\r\nReferring patient for work-up and mastoidectomy of the left ear as service case. \r\nPlease refer to Otology specialty once with complete labs and CT scan. \r\nPlease inform me once patient is seen at the OPD. \r\nThank you.','2026-02-03 11:39:03'),(8,0,2590,'To: Department of ORH-HNS\r\nReferring patient for scheduling of operation for mastoidectomy, AS under general anesthesia c/o Medicard. \r\nThank you.','2026-02-09 13:56:22'),(9,0,2590,'to: Iloilo Mission Hospital\r\nRadiology Department\r\n\r\nPlease give CD/USB copy of patien\'s CT scan taken last 2-4-26.\r\nThank you.','2026-02-09 13:58:56'),(10,0,2883,'TO: MEDICUS AMBULATORY HEALTHCARE\r\n8TH FLOOR MEDICUS CONDO BUILDING\r\nMANDURRIAO ILOILO CITY\r\n\r\nCC: HOARSENESS\r\nIMPRESSION: VOCAL CORD EDEMA\r\n\r\n>PLEASE ACCOMODATE PATIENT FOR FLEXIBLE LARYNGOSCOPY UNDER LOCAL ANESTHESIA\r\n>DECONGEST PRIOR TO PROCEDURE\r\n>PLEASE INFORM ME ONCE PATIENT IS IN\r\n>THANK YOU','2026-02-12 13:18:07'),(11,0,2912,'TO: DEPARTMENT OF ORL-HNS (WESTERN VISAYAS MEDICAL CENTER) / (ST. PAUL\'S HOSPITAL)\r\n\r\nREFERRING PATIENT FOR TONSILLECTOMY. HE HAS GRADE 4 TONSLS BILATERAL WITH OBSTRUCTIVE SLEEP APNEA AS SERVICE.\r\nHE CAME TOMYCLINIC FOR PRE-EMPLOYMENT CLEARANCE HOWEVER, I SUGGESTED OPERATION BEFORE HE IS CLEARED FOR WORK, THUS THIS REFERRAL.\r\nTHANK YOU.','2026-02-16 12:50:30'),(12,0,2796,'ENT CLEARANCE\r\n\r\n\r\nTHIS IS TO CERTIFY THAT PATIENT MAY GO AHEAD WITH PLANNED CT SCAN OF THE NECK, CHEST AND WHOLE ABDOMEN (WITH CONTRAST) AS MONITORING FOR HIS PANCREATIC CANCER AND THYROID NODULES. \r\n\r\n\r\nATTACHED ARE THE RESULTS OF HIS THYROID FUNCTION TEST AND SERUM CREATININE.\r\n\r\nTHANK YOU.','2026-02-19 10:48:30'),(13,0,3022,'TO:\r\nWESTERN VISAYAS MEDICAL CENTER\r\nDEPARTMENT OF ORL-HNS\r\nOUT PATIENT DEPARTMENT\r\n\r\nREFERRING PATIENT FOR INCISION BIOPSY OF LOWER LIP MASS.\r\nFOR CLEARANCE PRIOR TO PROCEDURE. \r\nPLEASE INFORM ME ONCE PATIENT IS SEEN. \r\nTHANK YOU.','2026-03-03 12:07:37'),(14,0,2911,'TO: SPH SPARC\r\nC/O DR. FERMINDOZA (ENT RESIDENT)\r\n\r\nPLEASE ACCOMODATE PATIENT FOR VIEO STROBOSCOPY UNDER LOCAL ANESTHESIA.\r\nDECONGEST PRIOR TO PROCEDURE.\r\nINFORM ME ONCE PATIENT IS IN.\r\nTHANK YOU.','2026-03-05 13:18:13'),(15,0,2801,'cc: mass lower lip\r\nimpression: mucocele right lower lip\r\n\r\nTo: \r\nMedicus Ambulatory Healthcare \r\ndiversion Road, Mandurriao Iloilo City\r\n8th Floor condo building\r\n\r\nPlease accomodate patient for excision of mass lower lip under localanesthesia on March 11, 2026 8:00 am.\r\nSecure signed consent. \r\nInform me once patient is in. \r\nThank you.','2026-03-05 15:21:43'),(16,0,3106,'TO: MEDICUS AMBULATORY HEALTHCARE\r\n8TH FLOR MEDICUS CONDO CLINIC\r\nDIVERSION ROAD ILOILO CITY\r\n\r\nCC: HOARSENESS\r\nIMPRESSION: LARYNGO-PHARYNGEAL REFLUX\r\n\r\nPLEASE ACCOMODATE PATIENT FOR FLEXIBLE LARYNGOSCOPY UNDER LOCAL ANESTHESIA\r\nDECONGEST PRIOR TO OPERATION\r\nPLEASE INFORM ME ONCE PATIENT IS IN. \r\nTHANK YOU.','2026-03-10 13:37:10'),(17,0,2911,'TO: SPH CRC \r\n\r\nPLEASE ACCOMODATE PATIENT FOR VIDEO STROBOSCOPY ON MARCH 25, 2026 AT 9 AM UNDER LOCAL ANESTHESIA\r\nDECONGEST PATIENT PRIOR TO PROCEDURE.\r\nPLEASE INFORM ME ONCE PATIENT IS IN. \r\nTHANK YOU.','2026-03-23 12:43:48'),(18,0,2482,'TO: SPH \r\nCRC DEPARTMENT\r\n\r\nCC: HOARSENESS\r\nIMPRESSION: LARYNGO-PHARYNGEAL REFLUX WITH VOCAL CORDS EDEMA\r\n\r\nPLEASE ACCOMODATE PATIENT FOR VIDEO STROBOSCOPY ON APRIL 13, 2026 9:00 AM\r\nDECONGEST PATIENT PRIOR TO PROCEDURE.\r\nINFORM ME ONCE PATIENT IS IN.','2026-03-27 13:00:05'),(19,0,3341,'TO: MEDICUS AMBULATORY HEALTHCARE\r\n\r\nCC: MASS LEFT EAR LOBE\r\nIMPRESSION: SEBACEOUS CYST LEFT EAR LOBE\r\n\r\nPLEASE ACCOMODATE PATIENT FOR EXCISION OF MASS LEFT EAR LOBE UNDER LOCAL ANESTHESIA ON APRIL 10, 2026 AT 9:00AM\r\nPLEASE SECURE SIGNED CONSENT. \r\nINFORM ME ONCE PATIENT IS IN.\r\nTHANK YOU.','2026-03-28 12:37:24'),(20,0,2923,'TO: SPH CRC\r\n\r\nCC: BLOOD TINGED SPUTUM WITH THROAT DISCOMFORT\r\nIMPRESSION: FUNGAL LARYNGITIS CANDIDIASIS, LARYNGO-PHARYNGEAL REFLUX\r\n\r\nPLEASE ACCOMODATE PATIENT FOR FLEXIBLE LARYNGOSCOPY UNDER LOCAL ANESTHESIA ON APRIL 13, 2026 9:30 AM \r\nPLEASE DECONGEST PRIOR TO PROCEDURE.\r\nINFORM ME ONCE PATIENT IS IN.\r\nTHANK YOU.','2026-03-31 12:25:54');
