DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_patients_before_insert` BEFORE INSERT ON `patients` FOR EACH ROW BEGIN
    -- Calculate age from birth_date
    IF NEW.birth_date IS NOT NULL THEN
        SET NEW.age = TIMESTAMPDIFF(YEAR, NEW.birth_date, CURDATE());
    ELSE
        SET NEW.age = NULL;
    END IF;
END */;;
